(function(window2, document2) {
  var shakeObj = {
    // 摇一摇加锁 防止重复触发
    shakeFlag: true,
    // 初始化
    init: function() {
      this.handleShake();
    },
    // 摇一摇
    handleShake: function() {
      if (window2.DeviceMotionEvent) {
        window2.addEventListener("devicemotion", deviceMotionHandler, false);
      } else {
        alert("该浏览器不支持摇一摇功能");
      }
      let SHAKETHRESHOLD = 4e3;
      let lastUpdate = 0;
      let x, y, z, lastX = 0, lastY = 0, lastZ = 0;
      let shakeAudio = document2.getElementById("shakemusic");
      let openAudio = document2.getElementById("openmusic");
      const self = this;
      function deviceMotionHandler(eventData) {
        let acceleration = eventData.accelerationIncludingGravity;
        let curTime = (/* @__PURE__ */ new Date()).getTime();
        if (curTime - lastUpdate > 50) {
          let diffTime = curTime - lastUpdate;
          lastUpdate = curTime;
          x = acceleration.x;
          y = acceleration.y;
          z = acceleration.z;
          let speed = Math.abs(x + y + z - lastX - lastY - lastZ) / diffTime * 1e4;
          if (speed > SHAKETHRESHOLD) {
            if (self.shakeFlag) {
              self.shakeFlag = false;
              self.useVibrateAction();
              shakeAudio.play();
              let shakeHandImg = document2.getElementById(
                "shakeHandImg"
              );
              shakeHandImg.classList.add("tada");
              shakeHandImg.classList.add("animated");
              shakeHandImg.addEventListener(
                "animationend",
                () => {
                  shakeHandImg.classList.remove("tada");
                  shakeHandImg.classList.remove("animated");
                }
              );
              setTimeout(() => {
                shakeAudio.pause();
                openAudio.play();
                alert("恭喜你，摇到漂亮妹纸一枚!");
                self.shakeFlag = true;
              }, 1e3);
            }
          }
          lastX = x;
          lastY = y;
          lastZ = z;
        }
      }
    },
    // 调用手机振动功能
    useVibrateAction() {
      navigator.vibrate = navigator.vibrate || navigator.webkitVibrate || navigator.mozVibrate || navigator.msVibrate;
      if (navigator.vibrate) {
        console.log("手机振动");
        navigator.vibrate(1e3);
      } else {
        console.log("该浏览器不支持振动功能");
      }
    }
  };
  shakeObj.init();
})(window, document);
